/* Layout reflows for whatever orientation the user is in */
.app {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(16rem, 1fr));
}

/* Hides the app and forces rotation in portrait */
@media (orientation: portrait) {
  .app { display: none; }
  .rotate-warning { display: block; }
}
